const metadataItems = $items('Select Changed KB File').map((item) => item.json || {});
const chunkItems = $input.all().map((item) => item.json || {});
const chunksByFileId = new Map();

function driveFileUrl(fileId, existingUrl = '') {
  if (existingUrl) return existingUrl;
  if (!fileId || String(fileId).startsWith('unknown_file_')) return '';
  return `https://drive.google.com/file/d/${fileId}/view`;
}

function plainSheetText(value = '') {
  return String(value || '').trim() || 'unknown_file_name';
}

function singaporeTimestamp(date = new Date()) {
  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: "Asia/Singapore",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false
  }).formatToParts(date).reduce((acc, part) => {
    if (part.type !== "literal") acc[part.type] = part.value;
    return acc;
  }, {});

  return parts.year + "-" + parts.month + "-" + parts.day + " " + parts.hour + ":" + parts.minute + ":" + parts.second + " SGT";
}

for (const chunk of chunkItems) {
  const metadata = chunk.metadata || {};
  const fileId = metadata.source_file_id || chunk.source_file_id || chunk.file_id;
  if (!fileId) continue;
  chunksByFileId.set(fileId, (chunksByFileId.get(fileId) || 0) + 1);
}

const uniqueMetadataItems = [];
const seenMetadataKeys = new Set();

for (const metadata of metadataItems) {
  const fileId = String(metadata.source_file_id || metadata.id || '').trim();
  const fileName = String(metadata.source_file_name || metadata.name || '').trim().toLowerCase();
  const key = fileId || fileName;

  if (key && seenMetadataKeys.has(key)) continue;
  if (key) seenMetadataKeys.add(key);

  uniqueMetadataItems.push(metadata);
}

return uniqueMetadataItems.map((metadata, index) => {
  const fileId = metadata.source_file_id || metadata.id || `unknown_file_${index + 1}`;
  const rawFileName = metadata.source_file_name || metadata.name || 'unknown_file_name';
  const fileUrl = driveFileUrl(fileId, metadata.google_drive_url);
  let chunksCount = chunksByFileId.get(fileId);

  if (chunksCount === undefined && metadataItems.length === 1) {
    chunksCount = chunkItems.length;
  }

  return {
    json: {
      file_id: fileId,
      file_name: plainSheetText(rawFileName),
      file_url: fileUrl,
      event_type: metadata.event_type || 'unknown',
      status: 'completed',
      chunks_count: chunksCount ?? '',
      namespace: metadata.namespace || 'SpaceKonceptRental_kb',
      modified_time: metadata.modified_time || '',
      ingestion_key: metadata.ingestion_key || '',
      execution_id: $execution.id,
      ingested_at: singaporeTimestamp(),
      error_message: ''
    }
  };
});

const seen = new Set();
const output = [];

for (const item of $input.all()) {
  const json = item.json || {};
  const fileId = String(json.id || json.fileId || '').trim();
  const fileName = String(json.name || json.fileName || '').trim().toLowerCase();
  const key = fileId || fileName;

  if (key && seen.has(key)) continue;
  if (key) seen.add(key);

  output.push(item);
}

return output;

const PINECONE_KB_NAMESPACE = 'SpaceKonceptRental_kb';
const hostItems = $input.all();
const sourceItems = $items('Select Changed KB File');

return hostItems.map((hostItem, index) => {
  const sourceItem = sourceItems[index] || {};
  const sourceJson = sourceItem.json || {};
  const hostJson = hostItem.json?.body || hostItem.json || {};
  const rawHost = hostJson.host || hostJson.database?.host || '';
  const host = String(rawHost).replace(/^https?:\/\//, '').replace(/\/$/, '');
  const namespace = sourceJson.namespace || PINECONE_KB_NAMESPACE;
  const rawFileId = String(sourceJson.source_file_id || '').trim();
  const fileId = rawFileId && !rawFileId.startsWith('unknown_file_') ? rawFileId : '';
  const fileName = String(sourceJson.source_file_name || '').trim();
  const filenameFallbackReviewed = sourceJson.filename_fallback_reviewed === true || String(sourceJson.filename_fallback_reviewed || '').toLowerCase() === 'true';
  let filter;

  if (!host) {
    throw new Error('Pinecone index host was not returned by Resolve Pinecone Index Host');
  }

  if (namespace !== PINECONE_KB_NAMESPACE) {
    throw new Error(`Unexpected Pinecone namespace "${namespace}" for KB delete request`);
  }

  if (fileId) {
    filter = { source_file_id: { $eq: fileId } };
  } else if (fileName && filenameFallbackReviewed) {
    filter = { source_file_name: { $eq: fileName } };
  } else {
    throw new Error('Cannot delete stale Pinecone vectors without stable source_file_id. Filename fallback requires filename_fallback_reviewed=true after manual uniqueness review.');
  }

  return {
    json: {
      ...sourceJson,
      pinecone_index_host: host,
      pinecone_delete_url: `https://${host}/vectors/delete`,
      pinecone_delete_body: {
        namespace: PINECONE_KB_NAMESPACE,
        filter
      }
    },
    binary: sourceItem.binary
  };
});

const deleteResults = $input.all();
const sourceItems = $items('Prepare Pinecone Delete Request');

function responseStatus(result) {
  const error = result.error || {};
  const statusCode = Number(result.statusCode || result.status || error.statusCode || error.status || error.httpCode || 0);
  if (statusCode) return statusCode;
  return result.error ? 500 : 200;
}

function responseBody(result) {
  if (result.body !== undefined) return result.body;
  if (result.error?.response?.body !== undefined) return result.error.response.body;
  if (result.error?.message) return { message: result.error.message };
  return result;
}

for (let index = 0; index < deleteResults.length; index += 1) {
  const result = deleteResults[index].json || {};
  const statusCode = responseStatus(result);
  const body = responseBody(result);
  const bodyText = typeof body === 'string' ? body : JSON.stringify(body);
  const message = typeof body === 'object' && body !== null ? String(body.message || body.error?.message || '') : bodyText;
  const isSuccess = statusCode >= 200 && statusCode < 300;
  const isFirstRunMissingNamespace = statusCode === 404 && /Namespace not found/i.test(message || bodyText);

  if (!isSuccess && !isFirstRunMissingNamespace) {
    const source = sourceItems[index]?.json || {};
    const fileRef = source.source_file_id || source.source_file_name || `item ${index + 1}`;
    throw new Error(`Pinecone delete failed for ${fileRef} (${statusCode}): ${bodyText}`);
  }
}

return sourceItems.map((item) => ({
  json: item.json,
  binary: item.binary
}));

const PINECONE_KB_NAMESPACE = 'SpaceKonceptRental_kb';
const sourceItems = $items('Prepare Chunk Metadata');
const lookupRows = $input.all().map((item) => item.json || {});

function clean(value) {
  return String(value ?? '').trim();
}

function stableFileId(source) {
  const fileId = clean(source.source_file_id);
  return fileId && !fileId.startsWith('unknown_file_') ? fileId : '';
}

function matchesCompletedIngestion(row, source) {
  const rowFileId = clean(row.file_id || row.source_file_id);
  const rowNamespace = clean(row.namespace) || PINECONE_KB_NAMESPACE;
  const rowIngestionKey = clean(row.ingestion_key);
  const rowModifiedTime = clean(row.modified_time);
  const sourceFileId = stableFileId(source);
  const sourceIngestionKey = clean(source.ingestion_key);
  const sourceModifiedTime = clean(source.modified_time);
  const status = clean(row.status).toLowerCase();

  if (!sourceFileId || rowFileId !== sourceFileId) return false;
  if (rowNamespace !== PINECONE_KB_NAMESPACE) return false;
  if (status !== 'completed') return false;

  return (rowIngestionKey && rowIngestionKey === sourceIngestionKey) ||
    (rowModifiedTime && sourceModifiedTime && rowModifiedTime === sourceModifiedTime);
}

const changedItems = [];

for (const sourceItem of sourceItems) {
  const source = sourceItem.json || {};
  const fileId = stableFileId(source);
  const ingestionKey = clean(source.ingestion_key);

  if (!fileId || !ingestionKey) {
    changedItems.push({
      json: {
        ...source,
        dedupe_lookup_status: 'missing_stable_key',
      },
      binary: sourceItem.binary,
    });
    continue;
  }

  if (lookupRows.some((row) => matchesCompletedIngestion(row, source))) {
    continue;
  }

  changedItems.push({
    json: {
      ...source,
      dedupe_lookup_status: 'changed_or_new',
    },
    binary: sourceItem.binary,
  });
}

return changedItems;
